  "$id": "https://github.com/Mega-Therion/OmegA-Architecture/schemas/omega_state.schema.json",
  "title": "OmegaState",
  "description": "Frozen kernel state: Ω_t = <Φ_t, E_t, τ_t, B_t, S_t, G_t^mem>",
  "type": "object",
  "required": ["phi", "envelope", "tau", "budget", "session", "memory_gate"],
  "properties": {
    "phi": { "$ref": "#/$defs/IdentityKernel" },
    "envelope": { "$ref": "#/$defs/RunEnvelope" },
    "tau": { "$ref": "#/$defs/TaskObject" },
    "budget": { "$ref": "#/$defs/ClaimBudget" },
    "session": { "$ref": "#/$defs/SessionRecord" },
    "memory_gate": { "$ref": "#/$defs/MemoryGate" }
  },
  "$defs": {
    "IdentityKernel": {
      "type": "object",
      "required": ["name", "doctrine", "phylactery_head"],
      "properties": {
        "name": { "type": "string" },
        "doctrine": { "type": "string" },
        "phylactery_head": { "type": "string", "description": "SHA-256 of the current identity commit" },
        "hard_constraints": { "type": "array", "items": { "type": "string" } },
        "version": { "type": "string" }
      }
    },
    "RunEnvelope": {
      "type": "object",
      "required": ["identity_kernel", "goal_contract", "governance_policy"],
      "properties": {
        "identity_kernel": { "$ref": "#/$defs/IdentityKernel" },
        "goal_contract": { "type": "string" },
        "governance_policy": { "type": "string", "enum": ["STANDARD", "STRICT", "MINIMAL"] },
        "memory_snapshot": { "type": "object" },
        "tool_manifest": { "type": "array", "items": { "type": "string" } },
        "audit_config": { "type": "object" }
      }
    },
    "TaskObject": {
      "type": "object",
      "required": ["id", "task", "status"],
      "properties": {
        "id": { "type": "string" },
        "task": { "type": "string" },
        "scope": { "type": "string" },
        "status": { "type": "string", "enum": ["pending", "running", "verified", "uncertain", "rejected", "complete"] },
        "constraints": { "type": "array", "items": { "type": "string" } },
        "success_criteria": { "type": "array", "items": { "type": "string" } },
        "created_at": { "type": "number" },
        "completed_at": { "type": ["number", "null"] }
      }
    },
    "ClaimBudget": {
      "type": "object",
      "properties": {
        "claims": {
          "type": "array",
          "items": { "$ref": "#/$defs/Claim" }
        },
        "grounding_ratio": { "type": "number", "minimum": 0, "maximum": 1 }
      }
    },
    "Claim": {
      "type": "object",
      "required": ["text", "support"],
      "properties": {
        "text": { "type": "string" },
        "support": { "type": "string", "enum": ["supported", "computed", "hypothetical", "unknown"] },
        "evidence": { "type": ["string", "null"] },
        "source_ref": { "type": ["string", "null"] },
        "confidence": { "type": ["number", "null"], "minimum": 0, "maximum": 1 }
      }
    },
    "SessionRecord": {
      "type": "object",
      "required": ["session_id", "started_at"],
      "properties": {
        "session_id": { "type": "string" },
        "started_at": { "type": "number" },
        "ended_at": { "type": ["number", "null"] },
        "provider": { "type": "string" },
        "model": { "type": "string" },
        "turn_count": { "type": "integer" },
        "continuity_source": { "type": "string", "enum": ["fresh", "restored", "repaired"] }
      }
    },
    "MemoryGate": {
      "type": "object",
      "properties": {
        "write_policy": { "type": "string", "enum": ["canonical", "working", "inferred", "speculative"] },
        "last_hardened": { "type": ["number", "null"] },
        "pending_write_count": { "type": "integer" }
      }
    }
  }
}

